    ) AS t(home_team, away_team, start_ts, ext_id, home_score, away_score, picks, offs)
  LOOP
    v_lock := rec.start_ts - interval '10 minutes';
    v_winner := CASE WHEN rec.home_score > rec.away_score
                     THEN rec.home_team ELSE rec.away_team END;

    INSERT INTO public.events (
      competition_id, tournament_id, event_name, sport,
      provider_league, external_event_id,
      start_time, lock_time, status,
      result_data, result_confirmed, result_confirmed_by
    ) VALUES (
      v_comp, v_tour,
      rec.home_team || ' v ' || rec.away_team,
      'baseball',
      'winter/lmp',
      rec.ext_id,
      rec.start_ts, v_lock, 'resulted',
      jsonb_build_object('home', rec.home_score, 'away', rec.away_score),
      true, v_admin
    ) RETURNING id INTO v_event_id;

    INSERT INTO public.event_prediction_types (event_id, prediction_type, points, config)
    VALUES (
      v_event_id, 'winner', 2,
      jsonb_build_object('options', jsonb_build_array(rec.home_team, rec.away_team))
    ) RETURNING id INTO v_ept_id;

    FOR i IN 1..8 LOOP
      INSERT INTO public.predictions (
        event_id, event_prediction_type_id, user_id, prediction_type,
        prediction_data, is_correct, is_partial, points_awarded,
        submitted_at, updated_at
      ) VALUES (
        v_event_id, v_ept_id, v_fans[i], 'winner',
        jsonb_build_object('value', rec.picks[i]),
        rec.picks[i] = v_winner, false,
        CASE WHEN rec.picks[i] = v_winner THEN 2 ELSE 0 END,
        v_lock - make_interval(mins => rec.offs[i]),
        v_lock - make_interval(mins => rec.offs[i])
      );
    END LOOP;
  END LOOP;

  RAISE NOTICE 'Backfilled LMP: 375 events, 375 EPTs, 3000 predictions';
END $$;
